Task: Simple Voting System

Specification: Create a single-winner voting contract with admin controls.
Requirements:
- Admin can register candidates with unique IDs
- Implement voter registration or allow any address to vote once
- Track vote counts per candidate using mapping
- Admin can end voting period (one-time action)
- Reject votes after voting ends or duplicate votes from same address
- Emit events for candidate registration, votes cast, and voting end
- Return winning candidate after voting ends
Security: Prevent admin from voting or manipulating results, validate candidate exists before voting

Faulty Contract:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.4;

contract VotingSystem {
    struct Candidate {
        uint voteCount;
    }

    mapping(address => bool) public voters;
    mapping(string => Candidate) public candidates;

    address public admin;
    bool public votingOpen = false;

    event VotedEvent(string candidate);
    event RegisteredCandidate(string candidate);
    event VotingEnded();

    constructor() {
        admin = msg.sender;
    }

    modifier onlyAdmin() {
        require(msg.sender == admin, "Only the admin can perform this action");
        _;
    }

    function registerCandidate(string memory candidate) public onlyAdmin {
        require(!votingOpen, "Voting is still open");
        candidates[candidate] = Candidate({voteCount: 0});
        emit RegisteredCandidate(candidate);
    }

    function vote(string memory candidate) public {
        require(votingOpen, "Voting period has ended");
        require(voters[msg.sender] == false, "You have already voted");
        require(candidates[candidate].voteCount > 0, "Candidate does not exist");

        voters[msg.sender] = true;
        candidates[candidate].voteCount += 1;

        emit VotedEvent(candidate);
    }

    function endVoting() public onlyAdmin {
        require(votingOpen, "Voting period has ended");
        votingOpen = false;

        emit VotingEnded();
    }

    function winner() public view returns (string memory) {
        require(!votingOpen, "Voting is still open");

        uint maxVotes = 0;
        string memory winner = "";

        for(uint i=0; i < candidates.length; i++){
            if(candidates[winner].voteCount < candidates[i].voteCount) {
                winner = candidates[i];
            }
        }

        return winner;
    }
}

