Task: Simple Voting System

Specification: Create a single-winner voting contract with admin controls.
Requirements:
- Admin can register candidates with unique IDs
- Implement voter registration or allow any address to vote once
- Track vote counts per candidate using mapping
- Admin can end voting period (one-time action)
- Reject votes after voting ends or duplicate votes from same address
- Emit events for candidate registration, votes cast, and voting end
- Return winning candidate after voting ends
Security: Prevent admin from voting or manipulating results, validate candidate exists before voting

Faulty Contract:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.4;

contract VotingSystem {
    // Mapping to store candidate details
    mapping(uint => Candidate) public candidates;

    // Structure for storing candidate data
    struct Candidate {
        uint id;
        string name;
        uint voteCount;
    }

    address public admin;
    bool public votingOpen;
    mapping(address => bool) public voters;

    event CandidacyRegistered (
        uint indexed _candidateId,
        string _name
    );

    event VoteCast (
         uint indexed _candidateId
    );

    constructor() {
        admin = msg.sender;
        votingOpen = true;
    }

    // Function to register candidate
    function registerCandidacy(uint _candidateId, string memory _name) public {
        require(msg.sender == admin, "Only the admin can register a candidate");
        require(!votingOpen, "Voting is still open for registration");

        candidates[_candidateId] = Candidate(_candidateId, _name, 0);

        emit CandidacyRegistered(_candidateId, _name);
    }

    // Function to cast vote
    function vote(uint _candidateId) public {
        require(votingOpen, "Voting is closed");
        require(!voters[msg.sender], "You have already voted");

        Candidate storage candidate = candidates[_candidateId];
        require(candidate.id != 0, "Candidate does not exist");

        voters[msg.sender] = true;
        candidate.voteCount++;

        emit VoteCast(_candidateId);
    }

    // Function to end voting and return winner
    function endVoting() public {
        require(msg.sender == admin, "Only the admin can end voting");
        votingOpen = false;

        Candidate memory winningCandidate;
        for (uint i = 1; i <= candidateCount; i++) {
            if (candidates[i].voteCount > winningCandidate.voteCount) {
                winningCandidate = candidates[i];
            }
        }

        emit VotingEnded(winningCandidate.id);
    }
}

