Task: Multi-Signature Wallet

Specification: Create a multi-signature wallet requiring multiple approvals.
Requirements:
- Initialize with array of owner addresses and required approval threshold
- Validate threshold <= number of owners and > 0
- Implement transaction proposal (target address, value, data)
- Track approvals per transaction using nested mappings
- Allow owners to approve transactions
- Execute transaction only when threshold met
- Prevent double-approvals from same owner
- Emit events for submissions, approvals, and executions
Security: Use call instead of transfer for execution, handle failed transactions, prevent reentrancy on execution

Faulty Contract:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.1;

contract MultiSigWallet {
    struct Transaction {
        address to;
        uint256 value;
        bytes data;
        bool executed;
    }

    mapping(address => bool) public owners;
    uint256 public requiredApprovals;
    mapping(address => mapping(uint256 => bool)) public approvals;
    Transaction[] public transactions;

    event Submitted(uint256 indexed txId);
    event Approved(uint256 indexed txId, address indexed owner);
    event Executed(uint256 indexed txId);

    constructor(address[] memory _owners, uint256 _requiredApprovals) {
        require(_owners.length > 0 && _requiredApprovals > 0 && _requiredApprovals <= _owners.length, "Invalid parameters");

        for (uint256 i = 0; i < _owners.length; ++i) {
            owners[_owners[i]] = true;
        }

        requiredApprovals = _requiredApprovals;
    }

    function submitTransaction(address _to, uint256 _value, bytes memory _data) public onlyOwner {
        transactions.push(Transaction({ to: _to, value: _value, data: _data, executed: false}));

        emit Submitted(transactions.length - 1);
    }

    function approveTransaction(uint256 _txId) public {
        require(!approvals[msg.sender][_txId], "Already approved");
        require(_txId < transactions.length, "Invalid transaction ID");

        approvals[msg.sender][_txId] = true;

        emit Approved(_txId, msg.sender);
    }

    function executeTransaction(uint256 _txId) public {
        require(transactions[_txId].executed == false, "Transaction already executed");
        require(getApprovalCount(_txId) >= requiredApprovals, "Not enough approvals");

        Transaction storage tx = transactions[_txId];
        tx.executed = true;

        // Use call instead of transfer to prevent reentrancy attacks
        (bool success, ) = tx.to.call{value: tx.value}(tx.data);
        require(success, "Transaction execution failed");

        emit Executed(_txId);
    }

