// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract Escrow {
    address public immutable buyer;
    address public immutable seller;
    address public immutable arbiter;
    uint256 public amount;
    State private state; // Use the enum directly

    enum State { Created, Delivered, Released, Refunded, Disputed }

    constructor(address _buyer, address _seller, address _arbiter, uint256 _amount) payable {
        require(_buyer != address(0), "Buyer must be a non-zero address.");
        require(_seller != address(0), "Seller must be a non-zero address.");
        require(_arbiter != address(0), "Arbiter must be a non-zero address.");
        require(_buyer != _seller, "Buyer and Seller addresses cannot be the same.");
        require(_buyer != _arbiter, "Buyer and Arbiter addresses cannot be the same.");
        require(_seller != _arbiter, "Seller and Arbiter addresses cannot be the same.");

        buyer = _buyer;
        seller = _seller;
        arbiter = _arbiter;
        amount = msg.value;
        state = State.Created;
    }

    function markDelivered() external {
        require(msg.sender == seller, "Only seller can mark item as delivered.");
        require(state == State.Created, "Contract must be in Created state to mark as Delivered.");

        state = State.Delivered;
        emit ItemDelivered();
    }

    function releasePayment() external {
        require(msg.sender == buyer, "Only buyer can release payment.");
        require(state == State.Delivered, "Contract must be in Delivered state to release payment.");

        // Use low-level call for deprecated transfer
        (bool success,) = payable(seller).call{value: amount}("");
        require(success, "Transfer failed.");

        state = State.Released;
        emit PaymentReleased();
    }

    function dispute() external {
        require(msg.sender == buyer, "Only buyer can initiate a dispute.");
        require(state == State.Delivered, "Contract must be in Delivered state to dispute.");

        state = State.Disputed;
        emit DisputeInitiated();
    }

    function arbiterResolve(address _winner) external {
        require(msg.sender == arbiter, "Only arbiter can resolve a dispute.");
        require(state == State.Disputed, "Contract must be in Disputed state to resolve.");

        if (_winner == buyer) {
            (bool success,) = payable(buyer).call{value: amount}("");
            require(success, "Transfer failed.");
            state = State.Refunded;
        } else if (_winner == seller) {
            (bool success,) = payable(seller).call{value: amount}("");
            require(success, "Transfer failed.");
            state = State.Released;
        }

        emit DisputeResolved(_winner);
    }

    event ItemDelivered();
    event PaymentReleased();
    event DisputeInitiated();
    event DisputeResolved(address indexed winner);
}

