// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract Escrow {
    address public buyer;
    address public seller;
    address public arbiter;
    uint256 public itemPrice;
    string private constant STATE_CREATED = "Created";
    string private constant STATE_DELIVERED = "Delivered";
    string private constant STATE_RELEASED = "Released";
    string private constant STATE_REFUNDED = "Refunded";
    string private constant STATE_DISPUTED = "Disputed";

    string public state;

    event ItemMarkedDelivered();
    event PaymentReleased(address indexed seller, uint256 amount);
    event RefundIssued(address indexed buyer, uint256 amount);
    event DisputeResolved(address indexed arbiter, address indexed winner, uint256 amount);

    constructor(
        address _buyer,
        address _seller,
        address _arbiter,
        uint256 _itemPrice
    ) payable {
        require(_buyer != address(0), "Buyer must be a non-zero address");
        require(_seller != address(0), "Seller must be a non-zero address");
        require(_arbiter != address(0), "Arbiter must be a non-zero address");
        require(_buyer != _seller, "Buyer and Seller addresses cannot be the same");
        require(_buyer != _arbiter, "Buyer and Arbiter addresses cannot be the same");
        require(_seller != _arbiter, "Seller and Arbiter addresses cannot be the same");

        buyer = _buyer;
        seller = _seller;
        arbiter = _arbiter;
        itemPrice = _itemPrice;

        state = STATE_CREATED;

        // Ensure exact Ether amount is deposited
        require(msg.value == itemPrice, "Exact Ether amount required");
    }

    function markItemDelivered() external {
        require(state == STATE_CREATED, "Contract must be in Created state to mark item delivered");
        require(msg.sender == seller, "Only seller can mark item as delivered");

        state = STATE_DELIVERED;
        emit ItemMarkedDelivered();
    }

    function releasePayment() external {
        require(state == STATE_DELIVERED, "Item must be marked Delivered to release payment");
        require(msg.sender == buyer, "Only buyer can request payment release");

        // Transfer Ether from contract to seller
        payable(seller).transfer(address(this).balance);

        state = STATE_RELEASED;
        emit PaymentReleased(seller, itemPrice);
    }

    function refundPayment() external {
        require(state == STATE_CREATED || state == STATE_DELIVERED, "Refund only allowed before or after delivery");
        require(msg.sender == buyer, "Only buyer can request a refund");

        // Refund Ether to the buyer
        payable(buyer).transfer(address(this).balance);

        if (state == STATE_CREATED) {
            state = STATE_REFUNDED;
        } else {
            state = STATE_RELEASED; // No change needed for already delivered items, just refund
        }

        emit RefundIssued(buyer, itemPrice);
    }

    function dispute() external {
        require(state == STATE_DELIVERED, "Dispute can only be initiated after delivery");
        require(msg.sender == buyer || msg.sender == seller, "Only buyer or seller can initiate a dispute");

        state = STATE_DISPUTED;
    }

    function arbiterResolveDispute(address payable winner) external {
        require(state == STATE_DISPUTED, "Dispute must be in Disputed state to resolve");
        require(msg.sender == arbiter, "Only arbiter can resolve the dispute");

        if (winner == seller) {
            // Transfer remaining Ether to seller
            payable(seller).transfer(address(this).balance);
            state = STATE_RELEASED;
        } else {
            // Transfer remaining Ether to buyer
            payable(buyer).transfer(address(this).balance);
            state = STATE_REFUNDED;
        }

        emit DisputeResolved(arbiter, winner, itemPrice);
    }
}

