        // Use low-level call instead of transfer
        (bool success,) = payable(seller).call{value: itemPrice}("");
        require(success, "Transfer failed.");

        emit PaymentReleased(seller, itemPrice);
    }

    function issueRefund() external {
        require(msg.sender == buyer, "Only buyer can request a refund.");
        require(stateCanTransition(currentState, STATE_REFUNDED), "Invalid state transition.");

        currentState = STATE_REFUNDED;

        // Use low-level call instead of transfer
        (bool success,) = payable(buyer).call{value: itemPrice}("");
        require(success, "Transfer failed.");

        emit RefundIssued(buyer, itemPrice);
    }

    function dispute() external {
        require(msg.sender == buyer, "Only buyer can initiate a dispute.");
        require(stateCanTransition(currentState, STATE_DISPUTED), "Invalid state transition.");

        currentState = STATE_DISPUTED;
    }

    function arbiterResolveDispute(address payable winner) external {
        require(msg.sender == arbiter, "Only arbiter can resolve disputes.");
        require(winner == seller || winner == buyer, "Winner must be either seller or buyer.");
        require(stateCanTransition(currentState, STATE_RELEASED), "Invalid state transition.");

        currentState = STATE_RELEASED;

        // Use low-level call instead of transfer
        (bool success,) = winner.call{value: itemPrice}("");
        require(success, "Transfer failed.");

        emit DisputeResolved(arbiter, winner, itemPrice);
    }

    function stateCanTransition(string memory from, string memory to) view internal returns (bool) {
        if (keccak256(abi.encodePacked(from)) == keccak256(abi.encodePacked(STATE_CREATED)) && 
            keccak256(abi.encodePacked(to))   == keccak256(abi.encodePacked(STATE_DELIVERED))) return true;
        if (keccak256(abi.encodePacked(from)) == keccak256(abi.encodePacked(STATE_DELIVERED)) && 
            keccak256(abi.encodePacked(to))   == keccak256(abi.encodePacked(STATE_RELEASED))) return true;
        if (keccak256(abi.encodePacked(from)) == keccak256(abi.encodePacked(STATE_DELIVERED)) && 
            keccak256(abi.encodePacked(to))   == keccak256(abi.encodePacked(STATE_REFUNDED))) return true;
        if (keccak256(abi.encodePacked(from)) == keccak256(abi.encodePacked(STATE_DISPUTED)) && 
            keccak256(abi.encodePacked(to))   == keccak256(abi.encodePacked(STATE_RELEASED))) return true;
        return false;
    }
}

