import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

contract VotingSystem {
    // Mapping to store candidate IDs and their vote counts
    mapping (address => uint256) public votes;

    // Mapping to store vote counts per candidate
    mapping (uint256 => uint256) public votesCount;

    // Mapping to store candidate registration status
    mapping (uint256 => bool) public candidatesRegistered;

    // Admin address for controlling the contract
    address public admin;

    // Event emitted when a new candidate is registered
    event CandidateRegistered(uint256 indexed _candidateId);

    // Event emitted when a vote is cast
    event VoteCast(address indexed _voter, uint256 indexed _candidateId);

    // Event emitted when voting period ends
    event VotingEnded();

    constructor() {
        admin = msg.sender;
    }

    // Function to register a new candidate
    function registerCandidate(uint256 _candidateId) public {
        require(msg.sender == admin, "Only admin can register candidates");
        require(!candidatesRegistered[_candidateId], "Candidate already registered");

        candidatesRegistered[_candidateId] = true;

        emit CandidateRegistered(_candidateId);
    }

    // Function to cast a vote
    function vote(uint256 _candidateId) public {
        require(msg.sender != admin, "Admin cannot vote");
        require(votes[msg.sender] == 0, "Duplicate vote from same address");

        votes[msg.sender] = _candidateId;
        votesCount[_candidateId] += 1;

        emit VoteCast(msg.sender, _candidateId);
    }

    // Function to end voting period
    function endVoting() public {
        require(msg.sender == admin, "Only admin can end voting");
        require(votes[msg.sender] != 0, "No votes cast yet");

        emit VotingEnded();
    }

    // Function to get the winning candidate
    function getWinner() public view returns (uint256) {
        uint256 maxVotes = 0;
        uint256 winnerId;

        for (uint256 i = 1; i <= 2**256 - 1; i++) { // Iterate over all possible IDs
            if (candidatesRegistered[i]) {
                if (votesCount[i] > maxVotes) {
                    maxVotes = votesCount[i];
                    winnerId = i;
                }
            }
        }

        return winnerId;
    }
}

