// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract Escrow {
    enum State { Created, Delivered, Released, Refunded, Disputed }

    struct Party {
        address addr;
        bool active;
    }

    mapping (address => Party) parties;

    uint256 public constant PAYMENT_RELEASED = 1 << 0;
    uint256 public constant ITEM_DELIVERED = 1 << 1;
    uint256 public constant DISPUTE_RESOLVED = 1 << 2;

    State public state;
    address public buyer;
    address public seller;
    address public arbiter;
    uint256 public amount;
    mapping (address => bool) public released;

    modifier onlyActive() {
        require(parties[msg.sender].active, "Only active parties can interact with the contract");
        _;
    }

    constructor(address _buyer, address _seller, address _arbiter) payable {
        require(_buyer != address(0), "_buyer cannot be zero address");
        require(_seller != address(0), "_seller cannot be zero address");
        require(_arbiter != address(0), "_arbiter cannot be zero address");

        buyer = _buyer;
        seller = _seller;
        arbiter = _arbiter;

        parties[buyer] = Party({addr: buyer, active: true});
        parties[seller] = Party({addr: seller, active: true});
        parties[arbiter] = Party({addr: arbiter, active: true});

        amount = msg.value;
    }

    function deliverItem() public onlyActive {
        require(state == State.Created, "Only in Created state can the item be delivered");
        state = State.Delivered;

        // Emit event for ItemDelivered
        emit ItemDelivered();
    }

    function releasePayment(address _party) public onlyActive {
        require(state == State.Delivered, "Only in Delivered state can payment be released");
        require(released[_party] == false, "Funds have already been released to this party");

        if (_party == buyer) {
            require(msg.sender == seller || msg.sender == arbiter, "Only seller or arbiter can release funds to buyer");
        } else if (_party == seller) {
            require(msg.sender == buyer || msg.sender == arbiter, "Only buyer or arbiter can release funds to seller");
        }

        released[_party] = true;

        // Emit event for PaymentReleased
        emit PaymentReleased(_party);
    }

    function resolveDispute(address _winner) public onlyActive {
        require(state == State.Delivered, "Only in Delivered state can disputes be resolved");

        if (_winner == buyer) {
            require(msg.sender == seller || msg.sender == arbiter, "Only seller or arbiter can resolve dispute in favor of buyer");
        } else if (_winner == seller) {
            require(msg.sender == buyer || msg.sender == arbiter, "Only buyer or arbiter can resolve dispute in favor of seller");
        }

        state = State.Disputed;

        // Emit event for DisputeResolved
        emit DisputeResolved(_winner);
    }

    function refund() public onlyActive {
        require(state == State.Delivered, "Only in Delivered state can funds be refunded");

        if (released[buyer] == false) {
            released[buyer] = true;
            payable(buyer).transfer(amount);
        } else if (released[seller] == false) {
            released[seller] = true;
            payable(seller).transfer(amount);
        }

        state = State.Refunded;

        // Emit event for Refund
        emit Refund();
    }

    function getContractState() public view returns (uint256) {
        return uint256(state);
    }

    event ItemDelivered();
    event PaymentReleased(address _party);
    event DisputeResolved(address _winner);
    event Refund();
}

