// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract SimpleVoting {
    struct Candidate {
        uint256 id;
        string name;
    }

    struct VoterRecord {
        bool hasVoted;
    }

    address public immutable owner;
    mapping(uint256 => Candidate) private candidates;
    mapping(address => VoterRecord) private voters;
    mapping(uint256 => uint256) private voteCounts;

    // Track registered candidate IDs to avoid collisions
    mapping(uint256 => bool) private isCandidateRegistered;

    bool public votingActive;
    uint256 public totalVotes;

    event CandidateRegistered(uint256 indexed candidateId, string name);
    event VoteCast(address indexed voter, uint256 candidateId);
    event VotingEnded(uint256 winnerCandidateId);

    constructor() {
        owner = msg.sender;
        votingActive = true; // Initialize voting as active
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner can perform this action");
        _;
    }

    function registerCandidate(uint256 id, string memory name) external onlyOwner {
        require(!isCandidateRegistered[id], "Candidate already exists");
        candidates[id] = Candidate({id: id, name: name});
        isCandidateRegistered[id] = true;
        emit CandidateRegistered(id, name);
    }

    function vote(uint256 candidateId) external payable {
        require(votingActive, "Voting is not active");
        require(isCandidateRegistered[candidateId], "Candidate does not exist");

        address voter = msg.sender;
        require(!voters[voter].hasVoted, "You have already voted");

        voters[voter] = VoterRecord(true);
        voteCounts[candidateId]++;
        totalVotes++;

        emit VoteCast(voter, candidateId);
    }

    function endVoting() external onlyOwner {
        require(votingActive, "Voting is already ended");
        votingActive = false;

        uint256 winnerId = getWinner();
        emit VotingEnded(winnerId);
    }

    function getWinner() public view returns (uint256) {
        require(!votingActive, "Voting must be ended to determine the winner");

        uint256 maxVotes = 0;
        uint256 winnerId = 0;

        // Iterate through all possible candidate IDs until an empty slot is found
        for (uint256 i = 1; ; i++) {
            if (!isCandidateRegistered[i]) break;
            if (voteCounts[i] > maxVotes) {
                maxVotes = voteCounts[i];
                winnerId = i;
            }
        }

        return winnerId;
    }

    function getVoteCount(uint256 candidateId) public view returns (uint256) {
        require(isCandidateRegistered[candidateId], "Candidate does not exist");
        return voteCounts[candidateId];
    }

    receive() external payable {}
}

