pragma solidity ^0.8.20;

contract Escrow {
    enum State { Created, Delivered, Released, Refunded, Disputed }
    enum DisputeResult { BuyerWins, SellerWins }

    struct ContractState {
        address buyer;
        address seller;
        address arbiter;
        uint256 depositAmount;
        bool itemDelivered;
        State currentState;
        DisputeResult disputeResult;
    }

    ContractState private _state;

    event StateChanged(address indexed buyer, address indexed seller, State previousState, State newState);
    event PaymentReleased(address indexed buyer, address indexed seller, uint256 amount);
    event Refunded(address indexed buyer, uint256 amount);
    event DisputeResolved(address indexed arbiter, DisputeResult result);

    constructor(
        address _buyer,
        address _seller,
        address _arbiter,
        uint256 _depositAmount
    ) payable {
        require(_buyer != address(0), "Buyer address cannot be zero");
        require(_seller != address(0), "Seller address cannot be zero");
        require(_arbiter != address(0), "Arbiter address cannot be zero");
        require(_buyer != _seller, "Buyer and seller must be different addresses");
        require(_buyer != _arbiter, "Buyer and arbiter must be different addresses");
        require(_seller != _arbiter, "Seller and arbiter must be different addresses");

        uint256 depositAmount = msg.value;
        require(depositAmount == _depositAmount, "Incorrect deposit amount");

        _state = ContractState({
            buyer: _buyer,
            seller: _seller,
            arbiter: _arbiter,
            depositAmount: depositAmount,
            itemDelivered: false,
            currentState: State.Created,
            disputeResult: DisputeResult.BuyerWins // Default value
        });
    }

    function getState() external view returns (ContractState memory) {
        return _state;
    }

    modifier onlyBuyer() {
        require(msg.sender == _state.buyer, "Only buyer can call this function");
        _;
    }

    modifier onlySeller() {
        require(msg.sender == _state.seller, "Only seller can call this function");
        _;
    }

    modifier onlyArbiter() {
        require(msg.sender == _state.arbiter, "Only arbiter can call this function");
        _;
    }

    modifier validState(State requiredState) {
        require(_state.currentState == requiredState, "Invalid contract state");
        _;
    }

    function markItemDelivered() external onlySeller validState(State.Created) {
        _state.itemDelivered = true;
        _state.currentState = State.Delivered;

        emit StateChanged(
            _state.buyer,
            _state.seller,
            State.Created,
            State.Delivered
        );
    }

    function releasePayment() external onlyBuyer validState(State.Delivered) {
        require(_state.itemDelivered, "Item not delivered");

        (bool success,) = payable(_state.seller).call{value: _state.depositAmount}("");
        require(success, "Transfer failed");

        _state.currentState = State.Released;

        emit PaymentReleased(
            _state.buyer,
            _state.seller,
            _state.depositAmount
        );
    }

    function dispute() external onlyBuyer validState(State.Delivered) {
        require(!_state.itemDelivered, "Item already delivered");

        _state.currentState = State.Disputed;

        emit StateChanged(
            _state.buyer,
            _state.seller,
            State.Delivered,
            State.Disputed
        );
    }

    function resolveDispute(DisputeResult result) external onlyArbiter validState(State.Disputed) {
        require(result == DisputeResult.BuyerWins || result == DisputeResult.SellerWins, "Invalid dispute result");

        _state.disputeResult = result;
        if (result == DisputeResult.BuyerWins) {
            _state.currentState = State.Refunded;

            (bool success,) = payable(_state.buyer).call{value: _state.depositAmount}("");
            require(success, "Transfer failed");

            emit Refunded(
                _state.buyer,
                _state.depositAmount
            );
        } else {
            _state.currentState = State.Released;

            (bool success,) = payable(_state.seller).call{value: _state.depositAmount}("");
            require(success, "Transfer failed");

            emit PaymentReleased(
                _state.buyer,
                _state.seller,
                _state.depositAmount
            );
        }

        emit DisputeResolved(
            _state.arbiter,
            result
        );
    }
}

