Task: Multi-Signature Wallet

Specification: Create a multi-signature wallet requiring multiple approvals.
Requirements:
- Initialize with array of owner addresses and required approval threshold
- Validate threshold <= number of owners and > 0
- Implement transaction proposal (target address, value, data)
- Track approvals per transaction using nested mappings
- Allow owners to approve transactions
- Execute transaction only when threshold met
- Prevent double-approvals from same owner
- Emit events for submissions, approvals, and executions
Security: Use call instead of transfer for execution, handle failed transactions, prevent reentrancy on execution

Faulty Contract:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract MultiSigWallet {
    struct Transaction {
        address target;
        uint256 value;
        bytes memory data;
        bool executed;
        mapping(address => bool) approvedBy;
    }

    address[] public owners;
    uint256 public requiredThreshold;
    mapping(address => bool) public isOwner;

    // Storage layout optimization
    Transaction[] private _transactions;
    mapping(uint256 => Transaction) private _transactionMap;
    uint256 private _nextTransactionId = 0;

    event WalletInitialized(address[] owners, uint256 threshold);
    event TransactionSubmitted(
        uint256 indexed transactionId,
        address target,
        uint256 value,
        string dataHash
    );
    event ApprovalGiven(uint256 indexed transactionId, address approver);
    event TransactionExecuted(uint256 indexed transactionId);

    constructor(address[] memory _owners, uint256 _threshold) {
        require(_threshold > 0, "Threshold must be greater than zero");
        require(_owners.length >= _threshold, "Threshold exceeds number of owners");

        for (uint i = 0; i < _owners.length; i++) {
            isOwner[_owners[i]] = true;
        }
        owners = _owners;
        requiredThreshold = _threshold;

        emit WalletInitialized(owners, requiredThreshold);
    }

    modifier onlyOwner() {
        require(isOwner[msg.sender], "Not an owner");
        _;
    }

    function submitTransaction(
        address target,
        uint256 value,
        bytes memory data
    ) external onlyOwner returns (uint256 transactionId) {
        require(target != address(this), "Cannot send to self");

        Transaction storage newTx = _transactionMap[_nextTransactionId];
        newTx.target = target;
        newTx.value = value;
        newTx.data = data;
        newTx.executed = false;

        emit TransactionSubmitted(
            _nextTransactionId,
            target,
            value,
            keccak256(abi.encodePacked(data))
        );

        return _nextTransactionId++;
    }

    function approveTransaction(uint256 transactionId) external onlyOwner {
        require(_transactionMap[transactionId].approvedBy[msg.sender] == false, "Already approved");
        require(!_transactionMap[transactionId].executed, "Transaction already executed");

        Transaction storage tx = _transactionMap[transactionId];
        tx.approvedBy[msg.sender] = true;

        emit ApprovalGiven(transactionId, msg.sender);
    }

    function executeTransaction(uint256 transactionId) external onlyOwner {
        require(_transactionMap[transactionId].executed == false, "Already executed");

        Transaction storage tx = _transactionMap[transactionId];
        uint256 approvalCount = 0;

        for (uint i = 0; i < owners.length; i++) {
            if (tx.approvedBy[owners[i]]) {
                approvalCount++;
            }
        }

        require(approvalCount >= requiredThreshold, "Insufficient approvals");

        tx.executed = true;
        emit TransactionExecuted(transactionId);

        // Use call with value to prevent reentrancy
        (bool success, ) = tx.target.call{value: tx.value}(
            abi.encodePacked(tx.data)
        );

        require(success, "Transaction execution failed");
    }

    function getApprovals(uint256 transactionId) external view returns (uint256 count) {
        Transaction storage tx = _transactionMap[transactionId];
        uint256 count = 0;

        for (uint i = 0; i < owners.length; i++) {
            if (tx.approvedBy[owners[i]]) {
                count++;
            }
        }

        return count;
    }

    function getTransaction(uint256 transactionId) external view returns (
        address target,
        uint256 value,
        bytes memory data,
        bool executed
    ) {
        Transaction storage tx = _transactionMap[transactionId];
        return (tx.target, tx.value, tx.data, tx.executed);
    }
}

