// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract RoleBasedAccessControl {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN");
    bytes32 public constant MANAGER_ROLE = keccak256("MANAGER");
    bytes32 public constant USER_ROLE = keccak256("USER");

    mapping(bytes32 => mapping(address => bool)) private _roles;
    address private _admin;

    event RoleGranted(bytes32 indexed role, address indexed account);
    event RoleRevoked(bytes32 indexed role, address indexed account);

    constructor() {
        _admin = msg.sender;
        _roles[ADMIN_ROLE][_admin] = true;
    }

    modifier onlyRole(bytes32 requiredRole) {
        require(_hasRole(requiredRole), "RBAC: insufficient access");
        _;
    }

    function grantRole(bytes32 role, address account) external onlyRole(ADMIN_ROLE) {
        require(account != address(0), "RBAC: invalid zero address");
        _roles[role][account] = true;
        emit RoleGranted(role, account);
    }

    function revokeRole(bytes32 role, address account) external onlyRole(ADMIN_ROLE) {
        require(_hasRole(role, account), "RBAC: insufficient access");
        _roles[role][account] = false;
        emit RoleRevoked(role, account);
    }

    function renounceRole(bytes32 role) external {
        require(msg.sender == _admin && role == ADMIN_ROLE, "RBAC: only admin can renounce admin role");
        _roles[ADMIN_ROLE][_admin] = false;
        delete _roles[role][msg.sender];
    }

    function getRoles(address account) public view returns (bytes32[] memory) {
        bytes32[] memory roles = new bytes32[](0);
        for (uint i = 0; i < 3; i++) {
            if (_hasRole(bytes32(i), account)) {
                roles.push(bytes32(i));
            }
        }
        return roles;
    }

    function hasRole(address account, bytes32 role) public view returns (bool) {
        return _roles[role][account];
    }

    function _hasRole(bytes32 role, address account) internal view returns (bool) {
        require(account != address(0), "RBAC: invalid zero address");
        return _roles[role][account];
    }

    function _hasRole(bytes32 role) internal view returns (bool) {
        return _hasRole(role, msg.sender);
    }

    // Sample functions demonstrating role requirements
    function adminOnlyFunction() external onlyRole(ADMIN_ROLE) pure returns (string memory) {
        return "Admin access granted";
    }

    function managerOnlyFunction() external onlyRole(MANAGER_ROLE) pure returns (string memory) {
        return "Manager access granted";
    }

    function userOnlyFunction() external onlyRole(USER_ROLE) pure returns (string memory) {
        return "User access granted";
    }

    // Fallback to prevent accidental sends
    fallback() external payable {
        revert("RBAC: no fallback allowed");
    }
}

