// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract SimpleVotingSystem {
    address public admin;
    bool public votingActive;
    mapping(uint256 => string) public candidates;
    mapping(address => uint256) public votes; // Corrected to map addresses to vote counts
    mapping(address => bool) public hasVoted;

    event CandidateRegistered(uint256 candidateId, string name);
    event VoteCast(address voter, uint256 candidateId);
    event VotingEnded(uint256 winningCandidateId);

    constructor() {
        admin = msg.sender;
    }

    modifier onlyAdmin() {
        require(msg.sender == admin, "Not authorized");
        _;
    }

    function registerCandidate(uint256 candidateId, string memory name) external onlyAdmin {
        require(keccak256(abi.encodePacked(candidates[candidateId])) != keccak256(abi.encodePacked("")), "Candidate already registered");
        candidates[candidateId] = name;
        emit CandidateRegistered(candidateId, name);
    }

    function vote(uint256 candidateId) external {
        require(votingActive, "Voting is not active");
        require(!hasVoted[msg.sender], "Already voted");
        require(keccak256(abi.encodePacked(candidates[candidateId])) != keccak256(abi.encodePacked("")), "Candidate does not exist");

        votes[msg.sender]++; // Corrected to use msg.sender as the key
        hasVoted[msg.sender] = true;
        emit VoteCast(msg.sender, candidateId);
    }

    function endVoting() external onlyAdmin {
        require(votingActive, "Voting is already ended");
        votingActive = false;

        uint256 maxVotes = 0;
        uint256 winningCandidateId = 0;

        for (uint256 i = 1; keccak256(abi.encodePacked(candidates[i])) != keccak256(abi.encodePacked("")); i++) {
            if (votes[msg.sender] > maxVotes) { // Corrected to use msg.sender as the key
                maxVotes = votes[msg.sender];
                winningCandidateId = i;
            }
        }

        emit VotingEnded(winningCandidateId);
    }
}

