    uint256 public transactionCount;

    event Submission(uint256 indexed transactionId, address indexed target, uint256 value, bytes data);
    event Approval(uint256 indexed transactionId, address indexed owner);
    event Execution(uint256 indexed transactionId);

    modifier onlyOwner() {
        require(isOwner[msg.sender], "Not an owner");
        _;
    }

    constructor(address[] memory _owners, uint256 _requiredApprovals) {
        require(_owners.length > 0 && _requiredApprovals > 0 && _requiredApprovals <= _owners.length, "Invalid parameters");

        for (uint256 i = 0; i < _owners.length; i++) {
