            emit RoleGranted(role, account);
        }
    }

    function revokeRole(bytes32 role, address account) external onlyAdmin {
        require(account != address(0), "Invalid address");
        if (_hasRole(role, account)) {
            _roles[role][account] = false;
            emit RoleRevoked(role, account);
        }
    }

    function renounceRole(bytes32 role) external {
        require(_hasRole(role, msg.sender), "Caller does not have the role to renounce");
        _roles[role][msg.sender] = false;
        emit RoleRevoked(role, msg.sender);
    }

    function isAdmin(address account) external view returns (bool) {
        return _isAdmin(account);
    }

    function checkRole(bytes32 role, address account) external view returns (bool) {
        return _hasRole(role, account);
    }

    function getAdmins() external view returns (address[] memory) {
        return _admins;
    }

    function _isAdmin(address account) internal view returns (bool) {
        for (uint i = 0; i < _admins.length; i++) {
            if (_admins[i] == account) {
