    address public arbiter;
    uint256 public amount;
    State public state;

    event EscrowCreated(address indexed buyer, address indexed seller, address indexed arbiter, uint256 amount);
    event ItemDelivered();
    event PaymentReleased();
    event DisputeResolved(address indexed resolver, uint256 amountToBuyer, uint256 amountToSeller);
    event RefundProcessed();

    constructor(address _buyer, address _seller, address _arbiter, uint256 _amount) payable {
        require(_buyer != address(0), "Buyer cannot be zero address");
        require(_seller != address(0), "Seller cannot be zero address");
        require(_arbiter != address(0), "Arbiter cannot be zero address");
        require(_buyer != _seller, "Buyer and seller cannot be the same");
        require(_buyer != _arbiter, "Buyer and arbiter cannot be the same");
        require(_seller != _arbiter, "Seller and arbiter cannot be the same");

        buyer = _buyer;
        seller = _seller;
        arbiter = _arbiter;
        amount = _amount;
        state = State.Created;

        emit EscrowCreated(_buyer, _seller, _arbiter, _amount);
    }

