        require(msg.sender == seller, "Only seller can mark delivered");
        require(state == State.Created, "Cannot mark delivered again");

        state = State.Delivered;
        emit ItemDelivered();
    }

    function releasePayment() external {
        require(msg.sender == buyer, "Only buyer can release payment");
        require(state == State.Delivered, "Cannot release payment yet");

        state = State.Released;
        payable(seller).transfer(amount);
        emit PaymentReleased();
    }

