        buyer = _buyer;
        seller = _seller;
        arbiter = _arbiter;
        deposit = msg.value;

        state = State.Created;
        emit EscrowCreated(_buyer, _seller, _arbiter, msg.value);
    }

    function deliver() external {
        require(state == State.Created, "Invalid state for deliver");
        state = State.Delivered;
        emit ItemDelivered();
    }

    function release() external {
        require(state == State.Delivered, "Invalid state for release");
        require(msg.sender == buyer, "Only buyer can release payment");
        state = State.Released;
        (bool success,) = seller.call{value: deposit}("");
        require(success, "Failed to send funds to seller");
        emit PaymentReleased();
    }

    function initiateDispute() external {
        require(state == State.Delivered, "Invalid state for dispute initiation");
        require(msg.sender == buyer, "Only buyer can initiate dispute");
        state = State.Disputed;
        emit DisputeInitiated();
    }

    function resolveDispute(bool isRefund) external {
        require(msg.sender == arbiter, "Only arbiter can resolve disputes");
        require(state == State.Disputed, "Invalid state for dispute resolution");

        if (isRefund) {
            state = State.Refunded;
            (bool success,) = buyer.call{value: deposit}("");
            require(success, "Failed to refund buyer");
            emit DisputeResolved(msg.sender, true);
        } else {
            state = State.Released;
            (bool success,) = seller.call{value: deposit}("");
            require(success, "Failed to send funds to seller");
            emit DisputeResolved(msg.sender, false);
        }
    }
}

