pragma solidity ^0.8.0;

contract MultiSigWallet {
    uint256 public threshold;
    address[] public owners;
    uint256 public transactionCount;
    mapping(uint256 => mapping(address => bool)) public approvals;
    mapping(uint256 => bool) public executed;

    event TransactionSubmitted(uint256 indexed txId, address target, uint256 value, bytes data);
    event ApprovalRegistered(uint256 indexed txId, address approver);
    event TransactionExecuted(uint256 indexed txId, address target, uint256 value, bytes data);

    constructor(address[] memory _owners, uint256 _threshold) {
        require(_threshold > 0 && _threshold <= _owners.length, "Invalid threshold");
        threshold = _threshold;
        owners = _owners;
    }

    function submitTransaction(address target, uint256 value, bytes memory data) public {
        transactionCount++;
        emit TransactionSubmitted(transactionCount, target, value, data);
    }

    function approveTransaction(uint256 txId) public {
        require(!executed[txId], "Transaction already executed or cancelled");
        require(!approvals[txId][msg.sender], "Already approved");
        require(isOwner(msg.sender), "Not an owner");

        approvals[txId][msg.sender] = true;
        emit ApprovalRegistered(txId, msg.sender);

        uint256 approvesReceived = 0;
        for (uint256 i = 0; i < owners.length; i++) {
            if (approvals[txId][owners[i]]) {
                approvesReceived++;
            }
        }

        if (approvesReceived >= threshold) {
            executeTransaction(txId, target, value, data);
        }
    }

    function executeTransaction(uint256 txId, address target, uint256 value, bytes memory data) private {
        require(!executed[txId], "Transaction already executed");
        require(transactionCount >= txId && txId > 0, "Invalid transaction ID");
        require(approvals[txId][msg.sender] || isOwner(msg.sender), "Not enough approvals or not owner");

        uint256 approvesReceived = 0;
        for (uint256 i = 0; i < owners.length; i++) {
            if (approvals[txId][owners[i]]) {
                approvesReceived++;
            }
        }
        require(approvesReceived >= threshold, "Threshold not met");

        executed[txId] = true;
        (bool success, ) = target.call{value: value}(data);
        require(success, "Transaction execution failed");
        emit TransactionExecuted(txId, target, value, data);
    }

    function isOwner(address account) private view returns (bool) {
        for (uint256 i = 0; i < owners.length; i++) {
            if (owners[i] == account) {
                return true;
            }
        }
        return false;
    }
}

