pragma solidity ^0.8.x;

contract SimpleVoting {
    struct Candidate {
        uint256 voteCount;
    }

    address public admin;
    bool public votingEnded;
    mapping(uint256 => Candidate) public candidates;
    mapping(address => bool) public voters;
    mapping(address => uint256) public voterCandidates;

    event CandidateRegistered(uint256 candidateId);
    event VoteCast(address indexed voter, uint256 candidateId);
    event VotingEnded();

    constructor() {
        admin = msg.sender;
    }

    modifier onlyAdmin() {
        require(msg.sender == admin, "Only admin can call this function");
        _;
    }

    modifier votingNotEnded() {
        require(!votingEnded, "Voting has ended");
        _;
    }

    modifier notVoted(address voter) {
        require(voters[voter] == false, "Already voted");
        _;
    }

    modifier candidateExists(uint256 candidateId) {
