pragma solidity ^0.8.x;

contract MultiSigWallet {
    address[] public owners;
    uint256 public required;
    mapping(uint256 => bool) private executed;
    mapping(uint256 => Transaction) private transactions;

    struct Transaction {
        address target;
        uint256 value;
        bytes data;
        bool executed;
        uint256 approvalCount;
        mapping(address => bool) approvals;
    }

    event SubmitTransaction(
        uint256 indexed txId,
        address indexed owner,
        address indexed to,
        uint256 value,
        bytes data
    );

    event ApproveTransaction(
        uint256 indexed txId,
        address indexed owner,
        bool approved
    );

    event ExecuteTransaction(
        uint256 indexed txId,
        address indexed owner,
        bool success
    );

    constructor(address[] memory _owners, uint256 _required) {
        require(_required > 0 && _required <= _owners.length, "Invalid threshold");
        owners = _owners;
        required = _required;
    }

    function submitTransaction(
        address target,
        uint256 value,
        bytes calldata data
    ) public {
        uint256 txId = transactions.length;
        transactions[txId] = Transaction({
            target: target,
            value: value,
            data: data,
            executed: false,
            approvalCount: 0
        });
        emit SubmitTransaction(txId, msg.sender, target, value, data);
    }

    function approveTransaction(uint256 txId) public {
        require(transactions[txId].approvals[msg.sender] == false, "Already approved");
        transactions[txId].approvalCount++;
        transactions[txId].approvals[msg.sender] = true;
        emit ApproveTransaction(txId, msg.sender, true);
    }

    function executeTransaction(uint256 txId) public {
        Transaction storage tx = transactions[txId];
        require(!tx.executed, "Already executed");
        require(tx.approvalCount >= required, "Threshold not met");

        bool success;
        (success,) = tx.target.call{value: tx.value}(tx.data);

        if (success) {
            tx.executed = true;
            emit ExecuteTransaction(txId, msg.sender, true);
        } else {
            emit ExecuteTransaction(txId, msg.sender, false);
        }
    }

    function getOwners() external view returns (address[] memory) {
        return owners;
    }

    function getRequired() external view returns (uint256) {
        return required;
    }

